import scala.collection.mutable.PriorityQueue
import scala.collection.mutable

def solve(grid: Array[Array[Long]], k: Long): Long = {
    val m = grid.length
    val n = grid(0).length
    val directions = Array((0, 1), (1, 0))
    case class State(cost: Long, i: Int, j: Int, tele: Long)
    implicit val ord: Ordering[State] = Ordering.by(-_.cost)
    val heap = PriorityQueue[State]()
    heap.enqueue(State(0, 0, 0, k))
    val visited = mutable.Map[(Int, Int, Long), Long]()
    visited((0, 0, k)) = 0

    while (heap.nonEmpty) {
        val current = heap.dequeue()
        val cost = current.cost
        val i = current.i
        val j = current.j
        val tele = current.tele
        if (i == m - 1 && j == n - 1) {
            return cost
        }
        if (visited.getOrElse((i, j, tele), Long.MaxValue) < cost) {
            continue
        }
        // Normal moves
        for ((di, dj) <- directions) {
            val ni = i + di
            val nj = j + dj
            if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                val newCost = cost + grid(ni)(nj)
                if (newCost < visited.getOrElse((ni, nj, tele), Long.MaxValue)) {
                    visited((ni, nj, tele)) = newCost
                    heap.enqueue(State(newCost, ni, nj, tele))
                }
            }
        }
        // Teleport moves
        if (tele > 0) {
            for (x <- 0 until m; y <- 0 until n) {
                if ((x != i || y != j) && grid(x)(y) <= grid(i)(j)) {
                    if (cost < visited.getOrElse((x, y, tele - 1), Long.MaxValue)) {
                        visited((x, y, tele - 1)) = cost
                        heap.enqueue(State(cost, x, y, tele - 1))
                    }
                }
            }
        }
    }
    -1
}

def continue: Unit = ()
